INSERT INTO quiz_questions (set_id, question_id, question, options, correct_option_index, explanation, sort_order) VALUES
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_1', 'I ___ already ___ lunch. (have/eat)', '["have / eat","have / ate","have / eaten","has / eaten"]', 2, '현재완료: have + 과거분사(eaten).', 1),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_2', 'She ___ never ___ to Japan. (has/be)', '["has / be","has / been","have / been","has / went"]', 1, '현재완료: has + been.', 2),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_3', 'If I ___ rich, I would travel the world.', '["am","was","were","be"]', 2, '가정법 과거에서는 "were"를 씁니다.', 3),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_4', 'If it rains, I ___ stay home.', '["will","would","could","might"]', 0, '조건절(1형): If + 현재, will + 동사원형.', 4),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_5', '"look up"의 뜻은?', '["위를 보다","찾아보다","둘 다 맞음","정리하다"]', 2, '"look up"은 위를 보다 / (사전에서) 찾아보다.', 5),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_6', '"give up"의 뜻은?', '["주다","포기하다","돌려주다","나눠주다"]', 1, '"give up" = 포기하다.', 6),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_7', '"turn off"의 뜻은?', '["돌리다","켜다","끄다","돌아서다"]', 2, '"turn off" = (전원을) 끄다.', 7),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_8', '"put on"의 뜻은?', '["놓다","입다/쓰다","내려놓다","벗다"]', 1, '"put on" = (옷/모자 등을) 입다/쓰다.', 8),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_9', '"take off"의 뜻은?', '["이륙하다","벗다","둘 다 맞음","가져가다"]', 2, '"take off" = 이륙하다 / (옷을) 벗다.', 9),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_10', 'He is ___ than his brother. (tall)', '["tall","taller","tallest","more tall"]', 1, '비교급: -er (taller).', 10),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_11', 'She is the ___ student in class. (smart)', '["smart","smarter","smartest","most smart"]', 2, '최상급: -est (smartest).', 11),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_12', 'This book is ___ interesting than that one.', '["more","most","much","many"]', 0, '다음절 형용사 비교급: more + 형용사.', 12),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_13', 'The movie was ___ boring ___ I expected.', '["more / than","most / than","as / as","less / as"]', 0, '"more ~ than" = ~보다 더.', 13),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_14', 'I have been ___ here for 2 hours. (wait)', '["wait","waited","waiting","to wait"]', 2, '현재완료진행: have been + ~ing.', 14),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_15', 'The cake was ___ by my mom. (수동태)', '["make","made","making","makes"]', 1, '수동태: was + 과거분사(made).', 15),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_16', '"break down"의 뜻은?', '["고장나다","부수다","분해하다","모두 맞음"]', 3, '"break down"은 고장나다/부수다/분해하다 모두 가능.', 16),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_17', '"run out of"의 뜻은?', '["달려가다","벗어나다","다 떨어지다","도망치다"]', 2, '"run out of" = ~이 다 떨어지다.', 17),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_18', '"come up with"의 뜻은?', '["올라오다","생각해내다","따라잡다","만나다"]', 1, '"come up with" = (아이디어를) 생각해내다.', 18),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_19', '"look forward to"의 뜻은?', '["앞을 보다","기대하다","찾아보다","돌아보다"]', 1, '"look forward to" = ~을 기대하다.', 19),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_20', 'I wish I ___ speak French.', '["can","could","will","would"]', 1, '소망의 가정법: wish + 과거 (could).', 20),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_21', 'You ___ better study hard. (충고)', '["had","have","should","would"]', 0, '"had better" = ~하는 게 좋겠다.', 21),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_22', 'He ___ to be a doctor when he grows up.', '["want","wants","wanting","wanted"]', 1, '3인칭 단수 현재: wants.', 22),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_23', 'I ___ lived in Seoul since 2010.', '["have","has","had","am"]', 0, '현재완료 + since: have lived.', 23),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_24', 'She told me ___ she was tired.', '["what","which","that","who"]', 2, '명사절 접속사 "that".', 24),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_25', 'The man ___ is standing there is my father.', '["who","which","what","whose"]', 0, '사람 관계대명사: who.', 25),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_26', 'The book ___ I read was interesting.', '["who","which","what","whose"]', 1, '사물 관계대명사: which (또는 that).', 26),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_27', '"used to"의 의미는?', '["~에 익숙하다","~하곤 했다","사용하다","둘 다 맞음"]', 1, '"used to" = (과거에) ~하곤 했다.', 27),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_28', '"be used to"의 의미는?', '["~에 익숙하다","~하곤 했다","사용되다","사용하다"]', 0, '"be used to" = ~에 익숙하다.', 28),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_29', 'I will call you ___ I arrive.', '["since","until","when","during"]', 2, '"when" = ~할 때.', 29),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_30', '___ it was raining, we went outside.', '["Because","Although","If","Unless"]', 1, '"Although" = ~에도 불구하고.', 30),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_31', '"get along with"의 뜻은?', '["따라가다","사이좋게 지내다","극복하다","시작하다"]', 1, '"get along with" = ~와 사이좋게 지내다.', 31),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_32', '"figure out"의 뜻은?', '["알아내다","적어두다","빠져나가다","체형을 가꾸다"]', 0, '"figure out" = 알아내다/이해하다.', 32),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_33', 'Neither Tom ___ Jerry likes math.', '["or","and","nor","but"]', 2, '"Neither A nor B" 구문.', 33),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_34', 'Not only is she smart, ___ she is kind.', '["and","or","but also","so"]', 2, '"Not only ~ but also ~" 구문.', 34),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_35', '"경험"을 영어로?', '["Experience","Experiment","Expert","Expect"]', 0, '"Experience"는 경험입니다.', 35),
((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_36', '"실험"을 영어로?', '["Experience","Experiment","Expert","Expect"]', 1, '"Experiment"는 실험입니다.', 36),
