((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_38', '"환경"을 영어로?', '["Environment","Equipment","Entertainment","Encouragement"]', 0, '"Environment"는 환경입니다.', 38),
