((SELECT id FROM quiz_sets WHERE difficulty='INTERMEDIATE' AND category='english'), 'en_j_41', '"뜻밖의"를 영어로?', '["Unexpected","Expected","Usual","Normal"]', 0, '"Unexpected"는 뜻밖의입니다.', 41),
